func:test_error_propagation = int32() {
    Result<int32>:r = make_error_result();

    // Apply ?!: since Result is error, use default 99
    int32:result = r ?! 99i32;

    // Should be 99 (the default, since r is an error)
    if (result == 99i32) {
        pass(0i32);  // CORRECT: default used for error result
    }
    pass(1i32);  // WRONG: did not get expected default
};

// Test: ?! with success result unwraps to value
func:test_success_propagation = int32() {
    Result<int32>:r = make_success_result();

    // Apply ?!: since Result is Ok, unwrap to actual value
    int32:result = r ?! 99i32;

    // Should be 42 (the actual value)
    if (result == 42i32) {
        pass(0i32);  // CORRECT: actual value unwrapped
    }
    pass(1i32);  // WRONG: did not get actual value
