    Point2D:origin;
    Point2D:size;
};

struct:Window = {
    Rect:bounds;
    int32:z_order;
};

func:main = int32() {

    // --- Test 1: Two-level nesting: Rect contains Point2D ---
    Rect:r;
    r.origin.x = 10i32;
    r.origin.y = 20i32;
    r.size.x   = 800i32;
    r.size.y   = 600i32;

    if (r.origin.x != 10i32)  { pass(1i32); }
    if (r.origin.y != 20i32)  { pass(2i32); }
    if (r.size.x   != 800i32) { pass(3i32); }
    if (r.size.y   != 600i32) { pass(4i32); }

    // --- Test 2: Three-level nesting: Window contains Rect contains Point2D ---
    Window:win;
    win.bounds.origin.x = 100i32;
    win.bounds.origin.y = 200i32;
    win.bounds.size.x   = 1280i32;
    win.bounds.size.y   = 720i32;
    win.z_order         = 3i32;

