    if (win.bounds.origin.y != 200i32)  { pass(6i32); }
    if (win.bounds.size.x   != 1280i32) { pass(7i32); }
    if (win.bounds.size.y   != 720i32)  { pass(8i32); }
    if (win.z_order         != 3i32)    { pass(9i32); }

    // --- Test 3: Two independent Rect instances don't share state ---
    Rect:r2;
    r2.origin.x = 0i32;
    r2.origin.y = 0i32;
    r2.size.x   = 320i32;
    r2.size.y   = 240i32;

