    while (cycle < 1000i64) {
        // Fill phase: write 8 values
        int64:fi = 0i64;
        while (fi < capacity) {
            int64:idx = (head + fi) % capacity;
            buf[idx] = cycle * 100i64 + fi;
            fi = fi + 1i64;
        }

        // Verify phase: check all 8 values
        int64:vi = 0i64;
        while (vi < capacity) {
            int64:ridx = (head + vi) % capacity;
            int64:expected = cycle * 100i64 + vi;
            if (buf[ridx] != expected) {
                errors = errors + 1i64;
            }
            vi = vi + 1i64;
        }

        // Advance head (drain all)
        head = (head + capacity) % capacity;
        cycle = cycle + 1i64;
    }

    if (errors > 0i64) {
        pass(1i32);
    }

    if (cycle != 1000i64) {
        pass(2i32);
    }

    pass(0i32);
};

