    nit:n0 = 1;
    nit:n1 = 2;
    nit:n2 = -1;
    nit:n3 = 0;
    nit:n4 = 3;
    nyte:packA = aria_pack_nyte(n0, n1, n2, n3, n4);
    nyte:packB = aria_pack_nyte(n1, n0, n2, n4, n3);
    nyte:combined = nyte_interfere(packA, packB);
    // combined should not be ERR (values: 3, 3, -2, 3, 3 - all in [-4,4])
    bool:noErr = !nyte_is_err(combined);
    if (!noErr) { pass(2i32); }

    // Test nyte_phase_shift
    nit:phase = 1;
    nyte:shifted = nyte_phase_shift(packA, phase);
    // shifted[0] = 1+1=2, should be valid
    bool:shiftOk = !nyte_is_err(shifted);
    if (!shiftOk) { pass(3i32); }

    // Test wave_kleene_and (elementwise min)
    nit:ax = 2;
    nit:ay = -1;
    nit:az = 3;
    nit:bx = 1;
    nit:by = 2;
    nit:bz = -2;
    Wave9:wa = wave_from_spatial(ax, ay, az);
    Wave9:wb = wave_from_spatial(bx, by, bz);
    Wave9:wand = wave_kleene_and(wa, wb);
    // min(2,1)=1, min(-1,2)=-1, min(3,-2)=-2
    if (wand.x != 1)  { pass(4i32); }
    if (wand.y != -1) { pass(5i32); }
    if (wand.z != -2) { pass(6i32); }

    // Test wave_kleene_or (elementwise max)
