    // max(2,1)=2, max(-1,2)=2, max(3,-2)=3
    if (wor.x != 2) { pass(7i32); }
    if (wor.y != 2) { pass(8i32); }
    if (wor.z != 3) { pass(9i32); }

    // Test wave_err_guard (no ERR in valid wave)
    bool:noWaveErr = !wave_err_guard(wa);
    if (!noWaveErr) { pass(10i32); }

    pass(0i32);
};

