 * wave_ext_test.aria - Tests for extended wave.aria functions
 *
 * Covers: wave_from_full, wave_from_state, wave_dot,
 *         wave_distance_squared, wave_lerp, nyte_toString, wave9_toString
 */

use "stdlib/wave.aria".*;

func:failsafe = NIL(int32:err_code) { pass(NIL); };

func:main = int32() {
    int32:failures = 0;
    println("wave_ext_test start");

    // Shared nit constants (can't pass int32 literals as nit args)
    nit:n0  = 0;
    nit:n1  = 1;
    nit:n_1 = -1;
    nit:n2  = 2;
    nit:n_2 = -2;
    nit:n3  = 3;
    nit:n_3 = -3;
    nit:n4  = 4;

    // ── wave_from_full ───────────────────────────────────────────────────────
    Wave9:full = wave_from_full(n1, n2, n0, n_1, n3, n_2, n4, n_3, n1);
    if (!(full.r == n1))  { println("FAIL: wave_from_full.r");  failures = failures + 1; }
    if (!(full.s == n2))  { println("FAIL: wave_from_full.s");  failures = failures + 1; }
    if (!(full.t == n0))  { println("FAIL: wave_from_full.t");  failures = failures + 1; }
    if (!(full.u == n_1)) { println("FAIL: wave_from_full.u");  failures = failures + 1; }
    if (!(full.v == n3))  { println("FAIL: wave_from_full.v");  failures = failures + 1; }
    if (!(full.w == n_2)) { println("FAIL: wave_from_full.w");  failures = failures + 1; }
    if (!(full.x == n4))  { println("FAIL: wave_from_full.x");  failures = failures + 1; }
    if (!(full.y == n_3)) { println("FAIL: wave_from_full.y");  failures = failures + 1; }
    if (!(full.z == n1))  { println("FAIL: wave_from_full.z");  failures = failures + 1; }

    // ── wave_from_state ──────────────────────────────────────────────────────
    Wave9:state = wave_from_state(n3, n_2);
    if (!(state.r == n3))  { println("FAIL: wave_from_state.r");    failures = failures + 1; }
    if (!(state.s == n_2)) { println("FAIL: wave_from_state.s");    failures = failures + 1; }
    if (!(state.x == 0))   { println("FAIL: wave_from_state.x!=0"); failures = failures + 1; }

    // ── wave_dot ─────────────────────────────────────────────────────────────
    // unit vector in r-dim dotted with itself → 1
    Wave9:a_dot = wave_from_state(n1, n0);
    Wave9:b_dot = wave_from_state(n1, n0);
    int32:dot1 = wave_dot(a_dot, b_dot);
    if (!(dot1 == 1)) { println("FAIL: wave_dot same unit"); failures = failures + 1; }

    // (2,3,-1 in xyz) · itself = 4+9+1 = 14
    Wave9:a2 = wave_from_spatial(n2, n3, n_1);
    int32:dot2 = wave_dot(a2, a2);
    if (!(dot2 == 14)) { println("FAIL: wave_dot self"); failures = failures + 1; }

    // orthogonal waves → dot = 0
    Wave9:a3 = wave_from_spatial(n2, n0, n0);
    Wave9:b3 = wave_from_spatial(n0, n2, n0);
    int32:dot3 = wave_dot(a3, b3);
    if (!(dot3 == 0)) { println("FAIL: wave_dot orthogonal"); failures = failures + 1; }

    // ── wave_distance_squared ────────────────────────────────────────────────
    // dist²(zero, (3,4,0,...)) = 9+16 = 25
    Wave9:zero = wave_zero();
    Wave9:pt   = wave_from_spatial(n3, n4, n0);
    int32:d2   = wave_distance_squared(zero, pt);
    if (!(d2 == 25)) { println("FAIL: wave_distance_squared(0,pt)"); failures = failures + 1; }

    // dist from a wave to itself = 0
    int32:d_self = wave_distance_squared(pt, pt);
    if (!(d_self == 0)) { println("FAIL: wave_distance_squared self=0"); failures = failures + 1; }

    // ── wave_lerp ────────────────────────────────────────────────────────────
    // lerp(zero, (4,4,4,...), 50) → x = (0*50 + 4*50)/100 = 2
    Wave9:wfull = wave_from_spatial(n4, n4, n4);
    Wave9:lerp_half = wave_lerp(wave_zero(), wfull, 50);
    string:lh_str = wave9_toString(lerp_half);
    println("lerp_half=");
    println(lh_str);
    if (!(lerp_half.x == n2)) { println("FAIL: wave_lerp x=2"); failures = failures + 1; }
    if (!(lerp_half.y == n2)) { println("FAIL: wave_lerp y=2"); failures = failures + 1; }

    // t=0 gives a, t=100 gives b
    Wave9:lerp0   = wave_lerp(wave_zero(), wfull, 0);
    Wave9:lerp100 = wave_lerp(wave_zero(), wfull, 100);
    if (!(wave_equals(lerp0, wave_zero()))) { println("FAIL: wave_lerp t=0");   failures = failures + 1; }
    if (!(wave_equals(lerp100, wfull)))     { println("FAIL: wave_lerp t=100"); failures = failures + 1; }

    // ── nyte_toString ────────────────────────────────────────────────────────
    // nyte_from_wave stores: x, y, z, u, r → N5(nx,ny,nz,nu,nr)
    Wave9:ws = wave_from_full(n_2, n0, n0, n3, n0, n0, n1, n2, n_1);
    nyte:packed = nyte_from_wave(ws);
    string:ns = nyte_toString(packed);
    if (!(string_equals(ns, "N5(1,2,-1,3,-2)"))) {
        println("FAIL: nyte_toString");
        println(ns);
        failures = failures + 1;
    }

    // ── wave9_toString ───────────────────────────────────────────────────────
    Wave9:ws2 = wave_from_state(n1, n_1);
    string:ws_str = wave9_toString(ws2);
    if (!(string_equals(ws_str, "W9(1,-1,0,0,0,0,0,0,0)"))) {
        println("FAIL: wave9_toString");
        println(ws_str);
        failures = failures + 1;
    }

    // ── summary ──────────────────────────────────────────────────────────────
    if (failures == 0) {
        println("ALL WAVE EXT TESTS PASSED");
    }

    pass(failures);
};


