// Aria Math Utilities - Integration Test
// Medium-complexity program exercising:
//   - Multiple cooperating functions
//   - Recursion (Fibonacci)
//   - While loops (GCD, prime sieve, ipow)
//   - Result<T> with ? unwrap
//   - Boolean results
//   - Integer arithmetic (+, -, *, /, %)
//   - Early return via pass()
//   - Multiple verification assertions in main()

// ============================================================================
// Fibonacci: iterative (Aria does not support self-recursion)
// fib(0)=0, fib(1)=1, fib(10)=55
// ============================================================================
func:fib = int32(int32:n) {
    if (n == 0i32) { pass(0i32); }
    if (n == 1i32) { pass(1i32); }
    int32:a = 0i32;
    int32:b = 1i32;
    int32:i = 2i32;
    while (i <= n) {
        int32:next = a + b;
        a = b;
        b = next;
        i = i + 1i32;
    }
    pass(b);
};

// ============================================================================
// GCD: Euclidean algorithm
// Tests while loop, variable reassignment, modulo
// ============================================================================
func:gcd = int32(int32:a, int32:b) {
    int32:x = a;
    int32:y = b;
    while (y != 0i32) {
        int32:t = y;
        y = x % y;
        x = t;
    }
    pass(x);
};

// ============================================================================
// LCM: via GCD
// Tests using Result<T> from one function as input to calculation
// ============================================================================
func:lcm = int32(int32:a, int32:b) {
    Result<int32>:g_r = gcd(a, b);
    int32:g = g_r ? 1i32;
    pass((a / g) * b);
};

// ============================================================================
// Primality test: trial division
// Tests: multiple early returns, i*i <= n termination, modulo
// ============================================================================
func:is_prime = bool(int32:n) {
    if (n < 2i32) { pass(false); }
    if (n == 2i32) { pass(true); }
    if (n % 2i32 == 0i32) { pass(false); }
    int32:i = 3i32;
    while (i * i <= n) {
        if (n % i == 0i32) { pass(false); }
        i = i + 2i32;
    }
    pass(true);
};

// ============================================================================
// Count primes up to N (inclusive)
// Tests: calling bool-returning function in a loop
// ============================================================================
func:count_primes = int32(int32:limit) {
    int32:count = 0i32;
    int32:i = 2i32;
    while (i <= limit) {
        Result<bool>:r = is_prime(i);
        bool:p = r ? false;
        if (p) { count = count + 1i32; }
        i = i + 1i32;
    }
    pass(count);
};

// ============================================================================
// Integer power: base^exp via fast exponentiation (binary method)
// Tests: bit-level arithmetic, multiple assignments in a loop
// ============================================================================
func:ipow = int32(int32:base, int32:exp) {
    if (exp == 0i32) { pass(1i32); }
    int32:result = 1i32;
    int32:b = base;
    int32:e = exp;
    while (e > 0i32) {
        if (e % 2i32 == 1i32) { result = result * b; }
        b = b * b;
        e = e / 2i32;
    }
    pass(result);
};

// ============================================================================
// Absolute value
// ============================================================================
func:abs_val = int32(int32:n) {
    if (n < 0i32) { pass(-n); }
    pass(n);
};

// ============================================================================
// Integer min and max
// ============================================================================
func:imin = int32(int32:a, int32:b) {
    if (a < b) { pass(a); }
    pass(b);
};

func:imax = int32(int32:a, int32:b) {
    if (a > b) { pass(a); }
    pass(b);
};

// ============================================================================
// Integer division ceiling: ceil(a / b)
// ============================================================================
func:ceil_div = int32(int32:a, int32:b) {
    pass((a + b - 1i32) / b);
};

// ============================================================================
// Sum of digits of a non-negative integer
// ============================================================================
func:digit_sum = int32(int32:n) {
    int32:sum = 0i32;
    int32:remaining = n;
    while (remaining > 0i32) {
        sum = sum + (remaining % 10i32);
        remaining = remaining / 10i32;
    }
    pass(sum);
