    Result<int32>:r2 = get_value(false);
    if (r2.is_error) {  // !!bool == bool: same as r2.is_error
        score = score + 1i32;  // +1 = 2 (r2 failed, so is_error=true)
    }

    // Test 3: Negation with method calls (ensuring postfix still works)
    Result<int32>:r3 = get_value(true);
    bool:check = r3.is_error;  // Method access still works
