// sieve.aria — EXP-7 Sieve of Eratosthenes
//
// Exercises (new patterns not seen in EXP-1..6):
//   - Nested while loops with inner step > 1  (j = j + prime)
//   - int64 accumulator for counting (prime count)
//   - Loop from p*p upward (non-trivial inner start index)
//   - Specific spot-check lookups into the sieve array
//   - sqrt approximation via integer step (outer loop up to ~32)
//
// Algorithm (sieve of Eratosthenes, limit=1000):
//   1. Allocate composite[0..1000] = all 0
//   2. For p = 2..31: if composite[p]==0, mark p*p, p*p+p, ... as composite
//   3. Count i in 2..1000 where composite[i]==0  → expect 168
//
// Spot-check primes: 2, 3, 5, 7, 11, 13, 997
// Spot-check composites: 4, 9, 25, 100, 1000

use "../../stdlib/string_convert.aria".*;
use "../../stdlib/print_utils.aria".*;

extern func:malloc = wild int64*(int64:size);
extern func:free   = void(wild int64*:ptr);

func:failsafe = NIL(int32:code) { pass(NIL); };

// ── Sieve ─────────────────────────────────────────────────────────────────────
// Returns count of primes in [2, limit].
// composite[i] == 0 means i is prime; 1 means composite.
// Uses one int64 per slot (proven array pattern).
func:run_sieve = int64(int64:limit, int64->:composite) {
    // Initialise: everything not-composite
    int64:i = 0i64;
    while (i <= limit) {
        composite[i] = 0i64;
        i = i + 1i64;
    }

    // Mark multiples: outer loop p = 2 .. sqrt(limit)
    // sqrt(1000) < 32, so stopping at 32 is safe
    int64:p = 2i64;
    while (p <= 32i64) {
        if (composite[p] == 0i64) {
            // p is prime — mark all multiples starting at p*p
            int64:j = p * p;
            while (j <= limit) {
                composite[j] = 1i64;
                j = j + p;
            }
        }
        p = p + 1i64;
    }

    // Count primes
    int64:count = 0i64;
    int64:n = 2i64;
    while (n <= limit) {
        if (composite[n] == 0i64) {
            count = count + 1i64;
        }
        n = n + 1i64;
    }
    pass(count);
};

