// json_tokenizer.aria — EXP-1 JSON Tokenizer
//
// Exercises:
//   - C extern with string parameter (aria_string_byte_at)
//   - wild int64* heap arrays (malloc/free, lisp.aria pattern)
//   - passing string values to Aria functions
//   - while loops, multi-condition logic, early-pass via raw()
//   - result-propagation with drop() for NIL-returning functions
//
// ── Bug found ────────────────────────────────────────────────────────────────
// Bug #13: extern func taking `string` parameter — Aria passes AriaString*
//   (pointer to struct), NOT AriaString by value.
//   Root cause: ariac stores string locals as ptr (pointer to constant
//     %struct.AriaString), and passes that pointer directly.
//   IR shows: declare i64 @aria_string_byte_at(ptr, i64)
//             call i64 @aria_string_byte_at(ptr %s2, i64 0)
//   Fix: declare C function with `const AriaString*` first param, not value.
// ─────────────────────────────────────────────────────────────────────────────
//
// Hard-coded token type codes (stored as int64):
//   0=EOF  1={  2=}  3=[  4=]  5=:  6=,  7=STRING  8=NUMBER  9=TRUE  10=FALSE  11=NULL
//
// ASCII reference (used in comments throughout):
//   '{':123  '}':125  '[':91  ']':93  ':':58  ',':44
//   '"':34   '-':45   '.':46  ' ':32  '\t':9  '\n':10  '\r':13
//   '0':48   '9':57   't':116  'f':102  'n':110

use "../../stdlib/string_convert.aria".*;
use "../../stdlib/print_utils.aria".*;

extern func:malloc = wild int64*(int64:size);
extern func:free   = void(wild int64*:ptr);

// aria_string_byte_at — returns byte at index i in string s as int64.
// Returns -1 when out of bounds.  Defined in src/runtime/strings/byte_at.c.
extern func:aria_string_byte_at = int64(string:s, int64:i);

