            if (side == 1i32 && si < 7i64) { si += 1i64; }

            int8:wc = shade[si];

            // Paint wall strip centred vertically in the column
            int64:top    = (H - lh) / 2i64;
            int64:bottom = top + lh;
            int64:wr     = top;
            while (wr < bottom) {
                if (wr >= 0i64 && wr < H) {
                    fb[wr * ROW_STRIDE + x] = wc;
