    } else {
        drop(printlnString("[FAIL] Test 1: sort of reverse input wrong"));
        drop(printString("  data[0]  = ")); drop(printlnInt64(data[0i64]));
        drop(printString("  data[15] = ")); drop(printlnInt64(data[15i64]));
