    expected[1i64] = 2i64;
    drop(msort(data, 0i64, 1i64));
    bool:t4_ok = raw(arrays_equal(data, expected, 2i64));
    if (t4_ok) {
        drop(printlnString("[PASS] Test 4: two-element swap [2,1] → [1,2]"));
        pass_count = pass_count + 1i64;
    } else {
