        b[i] = 1i8;
        i += 1i64;
    }

    // Ranks 2-5: empty
    while (i < 48i64) {
        b[i] = 0i8;
        i += 1i64;
    }

    // Rank 6: black pawns  a7..h7
    while (i < 56i64) {
        b[i] = 7i8;
        i += 1i64;
    }

    // Rank 7: black back rank  a8..h8
    b[56i64] = 10i8;  // r
