    // ── Move 5: X takes left-middle (pos 3 = field u) ─────────────────────
    //   X now holds v(4) and u(3) — threatens middle row [u,v,w]!
    board.u = X;
    drop(println("Move 5 — X plays pos 3 (left-middle):"));
    drop(println("         X threatens middle row [3,4,5] — can O stop it?"));
    drop(print_board(board));
    // Intermediate check: no winner yet
    int32:w5 = raw(check_winner(board));
    if (w5 != 0i32) { pass(11i32); }  // unexpected early win = test failure
    drop(println("  (no winner yet)"));
    drop(println(""));

    // ── Move 6: O greedy AI — center=X, r=O, t=X, x=O → takes bottom-right (pos 8 = z) ──
    //   O misses X's threat on pos 5!
    board.z = O;
