    drop(println("         O grabs a corner instead of blocking pos 5!"));
    drop(print_board(board));
    drop(println(""));

    // ── Move 7: X takes right-middle (pos 5 = field w) ────────────────────
    //   X completes middle row [u(3), v(4), w(5)] = ALL X  → X WINS!
    board.w = X;
    drop(println("Move 7 — X plays pos 5 (right-middle):"));
    drop(print_board(board));
    drop(println(""));

    // ── Final result ──────────────────────────────────────────────────────
    int32:winner = raw(check_winner(board));

    if (winner == 1i32) {
        drop(println("X WINS! Middle row complete: positions 3-4-5."));
        drop(println("  Kleene AND: nit_and(nit_and(u, v), w) = 1"));
    }
    if (winner == -1i32) {
        drop(println("O WINS!"));
    }
    if (winner == 0i32) {
        drop(println("Draw."));
    }

    drop(println(""));
    drop(println("================================"));
    drop(println(" Game over. Thanks for playing! "));
    drop(println(" Doom port coming soon...       "));
    drop(println("================================"));
    drop(println(""));

    // Test assertion: this scripted game must end in X winning
    if (winner != 1i32) { pass(1i32); }

    pass(0i32);
};

