    // e1 = d + T1 = h3 + T1
    uint32:a1 = T1 + T2;
    uint32:e1 = 0xa54ff53au32 + T1;
    drop(print("a after round 0 = "));
    drop(println(int32_toHex(a1 => int32)));
    drop(print("e after round 0 = "));
    drop(println(int32_toHex(e1 => int32)));

    pass(0i32);
};

