/**
 * rpn_calc.aria  —  Reverse Polish Notation Calculator in Aria Lang
 *
 * Demonstrates: int64[N] stack array, string operator dispatch,
 * string_from_int display, divide-by-zero error detection.
 *
 * Stack: int64[16] local array + int32 top pointer.
 *   push(v):  stk[top] = v;  top = top + 1;
 *   pop():    top = top - 1;  v = stk[top];
 *
 * Expressions:
 *   Expr 1:  3 4 + 2 * 7 /       =>  ((3+4)*2)/7  = 2
 *   Expr 2:  5 1 2 + 4 * + 3 -   =>  5+((1+2)*4)-3  = 14
 *   Expr 3:  10 0 /               =>  divide-by-zero
 *
 * Compiler notes:
 *   WORKS: int64[N] local array + variable int32 index
 *   WORKS: string_equals(a,b) in if conditions
 *   WORKS: string_from_int(int64)
 *   WORKS: int64 arithmetic in functions (no cast needed)
 *   BUG:   @cast<int64>(int32) returns 1 (Result tag), not value
 *            -> use int64 throughout to avoid
 *   NOTE:  'stack' is a reserved keyword -> use 'stk'
 */

