func:main = int32() {
    int64[16]:stk;
    int32:top = 0;

    drop(println("=== RPN Calculator (Aria Lang) ==="));
    drop(println(""));

    // ── Expr 1:  3 4 + 2 * 7 /  =>  2 ───────────────────────────────────────
    drop(println("Expr 1:  3 4 + 2 * 7 /"));

    stk[top] = 3i64;  top = top + 1;
    stk[top] = 4i64;  top = top + 1;

    top = top - 1;  int64:e1b1 = stk[top];
    top = top - 1;  int64:e1a1 = stk[top];
    int64:e1r1 = raw(apply_op(e1a1, e1b1, "+"));
    stk[top] = e1r1;  top = top + 1;

    stk[top] = 2i64;  top = top + 1;

    top = top - 1;  int64:e1b2 = stk[top];
    top = top - 1;  int64:e1a2 = stk[top];
    int64:e1r2 = raw(apply_op(e1a2, e1b2, "*"));
    stk[top] = e1r2;  top = top + 1;

    stk[top] = 7i64;  top = top + 1;

    top = top - 1;  int64:e1b3 = stk[top];
    top = top - 1;  int64:e1a3 = stk[top];
    int64:e1r3 = raw(apply_op(e1a3, e1b3, "/"));
    stk[top] = e1r3;  top = top + 1;

    top = top - 1;
    int64:res1 = stk[top];
    drop(print_result("  Result: ", res1, "2"));
    drop(println(""));

    // ── Expr 2:  5 1 2 + 4 * + 3 -  =>  14 ──────────────────────────────────
    top = 0;
    drop(println("Expr 2:  5 1 2 + 4 * + 3 -"));

    stk[top] = 5i64;  top = top + 1;
    stk[top] = 1i64;  top = top + 1;
    stk[top] = 2i64;  top = top + 1;

    top = top - 1;  int64:e2b1 = stk[top];
    top = top - 1;  int64:e2a1 = stk[top];
    int64:e2r1 = raw(apply_op(e2a1, e2b1, "+"));
    stk[top] = e2r1;  top = top + 1;

    stk[top] = 4i64;  top = top + 1;

    top = top - 1;  int64:e2b2 = stk[top];
    top = top - 1;  int64:e2a2 = stk[top];
