// Complete Async/Await Example for Aria
// Demonstrates real-world async patterns

// Async file reading
async func:read_config = string(string:path) {
    // Future: This will use aria_read_file_async()
    string:content = await file_read(path);
    pass(content);
};

// Async data processing
async func:process_data = int64(string:data) {
    // Simulate async computation
    int64:result = data.length() * 2;
    pass(result);
};

// Chained async operations
async func:load_and_process = int64(string:config_path) {
    // Step 1: Read file asynchronously
    string:config = await read_config(config_path);

    // Step 2: Process data asynchronously
    int64:result = await process_data(config);

    // Step 3: Return final result
    pass(result + 100);
};

// Multiple parallel operations (using combinators)
async func:batch_process = int64() {
    // Start multiple async operations
    int64:task1 = process_task("/tmp/file1.txt");
    int64:task2 = process_task("/tmp/file2.txt");
    int64:task3 = process_task("/tmp/file3.txt");

    // Wait for first two
    int64:result1 = await task1;
    int64:result2 = await task2;

    // Third continues in background

    pass(result1 + result2);
};

// Conditional async execution
async func:smart_loader = string(string:cache_path, string:remote_url) {
    // Try cache first
    bool:exists = await file_exists(cache_path);

    if (exists) {
        // Use cached version
        pass(await read_config(cache_path));
    } else {
        // Download from remote
        string:content = await http_get(remote_url);

        // Save to cache (fire and forget)
        await file_write(cache_path, content);

        pass(content);
    }
};

// Error handling with async
async func:safe_read = Result<string>(string:path) {
    try {
        string:content = await read_config(path);
        pass(Ok(content));
    } catch (FileError:e) {
        pass(Err("Failed to read file: " + e.message));
    }
};

// Async with timeout
async func:timed_operation = Result<int64>(string:path) {
    // This would use aria_with_timeout()
    Result<int64>:result = await with_timeout(
        load_and_process(path),
        5000  // 5 second timeout
    );

    pass(result);
};

// Main entry point
func:main = int64() {
    // Example 1: Simple async
    int64:result1 = load_and_process("/tmp/config.json");

    // Example 2: Batch processing
    int64:result2 = batch_process();

    // Example 3: Smart caching
    string:data = smart_loader("/tmp/cache.txt", "https://api.example.com/data");

    // Example 4: With error handling
    Result<string>:safe_result = safe_read("/tmp/important.txt");

    if (safe_result.is_ok()) {
        print("Success: " + safe_result.unwrap());
    } else {
        print("Error: " + safe_result.unwrap_err());
    }

    pass(0);
};

/*
 * HOW THIS WORKS:
 * 
 * 1. Compiler generates LLVM coroutines for each async function
 * 2. Each await becomes a suspension point
 * 3. Runtime executor schedules and runs coroutines
 * 4. Future<T> manages async results
 * 5. Async I/O operations don't block execution
 * 
 * BENEFITS:
 * - Non-blocking I/O
 * - Easy to read/write (looks synchronous!)
 * - Efficient (no OS threads needed)
 * - Composable (chain operations easily)
 * - Type-safe (compiler checks await usage)
