    nit:r1_xab  = nit_and(b.u, b.v);
    nit:r1_xabc = nit_and(r1_xab, b.w);
    if (r1_xabc == 1) { pass(1i32); }
    nit:r1_na   = -b.u;
    nit:r1_nb   = -b.v;
    nit:r1_nc   = -b.w;
    nit:r1_oab  = nit_and(r1_na, r1_nb);
    nit:r1_oabc = nit_and(r1_oab, r1_nc);
