    board.w = X;
    drop(println("Move 7 — X plays pos 5 (right-middle):"));
    drop(print_board(board));
    drop(println(""));

    // ── Final result ──────────────────────────────────────────────────────
    int32:winner = raw(check_winner(board));

    if (winner == 1i32) {
        drop(println("X WINS! Middle row complete: positions 3-4-5."));
        drop(println("  Kleene AND: nit_and(nit_and(u, v), w) = 1"));
    }
    if (winner == -1i32) {
