use std.io;

// Token types
enum:TokenType = {
    TOK_EOF = 0,
    TOK_LBRACE = 1,           // {
    TOK_RBRACE = 2,           // }
    TOK_LBRACKET = 3,         // [
    TOK_RBRACKET = 4,         // ]
    TOK_COLON = 5,            // :
    TOK_COMMA = 6,            // ,
    TOK_STRING = 7,           // "string"
    TOK_NUMBER = 8,           // 123 or 45.67
    TOK_TRUE = 9,             // true
    TOK_FALSE = 10,           // false
    TOK_NULL = 11,            // null
    TOK_ERROR = 12            // Error
};

// Token structure
struct:Token = {
    int32:type;
    int32:line;
    int32:column;
};

