// json_tokenizer.aria — EXP-1 JSON Tokenizer
//
// Exercises:
//   - C extern with string parameter (aria_string_byte_at)
//   - wild int64* heap arrays (malloc/free, lisp.aria pattern)
//   - passing string values to Aria functions
//   - while loops, multi-condition logic, early-pass via raw()
//   - result-propagation with drop() for NIL-returning functions
//
// ── Bug found ────────────────────────────────────────────────────────────────
// Bug #13: extern func taking `string` parameter — Aria passes AriaString*
//   (pointer to struct), NOT AriaString by value.
//   Root cause: ariac stores string locals as ptr (pointer to constant
//     %struct.AriaString), and passes that pointer directly.
//   IR shows: declare i64 @aria_string_byte_at(ptr, i64)
//             call i64 @aria_string_byte_at(ptr %s2, i64 0)
//   Fix: declare C function with `const AriaString*` first param, not value.
// ─────────────────────────────────────────────────────────────────────────────
//
// Hard-coded token type codes (stored as int64):
//   0=EOF  1={  2=}  3=[  4=]  5=:  6=,  7=STRING  8=NUMBER  9=TRUE  10=FALSE  11=NULL
//
// ASCII reference (used in comments throughout):
//   '{':123  '}':125  '[':91  ']':93  ':':58  ',':44
//   '"':34   '-':45   '.':46  ' ':32  '\t':9  '\n':10  '\r':13
//   '0':48   '9':57   't':116  'f':102  'n':110

use "../../stdlib/string_convert.aria".*;
use "../../stdlib/print_utils.aria".*;

extern func:malloc = wild int64*(int64:size);
extern func:free   = void(wild int64*:ptr);

// aria_string_byte_at — returns byte at index i in string s as int64.
// Returns -1 when out of bounds.  Defined in src/runtime/strings/byte_at.c.
extern func:aria_string_byte_at = int64(string:s, int64:i);

func:failsafe = NIL(int32:code) { pass(NIL); };

// ── Classifiers ──────────────────────────────────────────────────────────────

func:is_ws = bool(int64:c) {
    pass(c == 32i64 || c == 9i64 || c == 10i64 || c == 13i64);
};

func:is_digit = bool(int64:c) {
    pass(c >= 48i64 && c <= 57i64);
};

// ── Tokenizer ────────────────────────────────────────────────────────────────
//
// state layout (4 elements):
//   state[0] = current byte position in input
//   state[1] = byte length of input
//   state[2] = number of tokens emitted so far
//   state[3] = (unused / reserved)
//
// next_tok reads one token starting at state[0], appends its type to
// ttypes[state[2]], then increments state[2].  Returns the token type.
//
// Token types (int64):
//   0=EOF  1={  2=}  3=[  4=]  5=:  6=,  7=STRING  8=NUMBER  9=TRUE  10=FALSE  11=NULL

func:next_tok = int64(int64->:state, string:input, int64->:ttypes) {
    // skip leading whitespace
    bool:ws_loop = true;
    while (ws_loop) {
        if (state[0i64] >= state[1i64]) {
            ws_loop = false;
        } else {
            int64:wc = aria_string_byte_at(input, state[0i64]);
            bool:is_space = raw(is_ws(wc));
            if (is_space) {
                state[0i64] = state[0i64] + 1i64;
            } else {
                ws_loop = false;
            }
        }
    }

    int64:pos = state[0i64];
    int64:len = state[1i64];
    int64:tc  = state[2i64];

    // EOF
    if (pos >= len) {
        ttypes[tc] = 0i64;
        state[2i64] = tc + 1i64;
        pass(0i64);
    }

    int64:ch = aria_string_byte_at(input, pos);
    int64:tok = 0i64 - 99i64;   // sentinel "unset"

    // ── Single-character tokens ──
    if (ch == 123i64) { tok = 1i64; state[0i64] = pos + 1i64; }  // {
    if (ch == 125i64) { tok = 2i64; state[0i64] = pos + 1i64; }  // }
    if (ch == 91i64)  { tok = 3i64; state[0i64] = pos + 1i64; }  // [
    if (ch == 93i64)  { tok = 4i64; state[0i64] = pos + 1i64; }  // ]
    if (ch == 58i64)  { tok = 5i64; state[0i64] = pos + 1i64; }  // :
    if (ch == 44i64)  { tok = 6i64; state[0i64] = pos + 1i64; }  // ,

    // ── String literal (34 = '"') ──
    if (ch == 34i64) {
        tok = 7i64;
        int64:sp = pos + 1i64;
        bool:str_loop = true;
        while (str_loop) {
            if (sp >= len) {
                str_loop = false;   // unterminated — treat as end
            } else {
                int64:sc = aria_string_byte_at(input, sp);
                sp = sp + 1i64;
                if (sc == 34i64) { str_loop = false; }  // closing "
            }
        }
        state[0i64] = sp;
    }

    // ── Number: starts with '-' (45) or a digit (48-57) ──
    bool:is_num_start = raw(is_digit(ch));
    if (ch == 45i64) { is_num_start = true; }
    if (is_num_start) {
        tok = 8i64;
        int64:np = pos + 1i64;
        bool:num_loop = true;
        while (num_loop) {
            if (np >= len) {
                num_loop = false;
            } else {
                int64:nc = aria_string_byte_at(input, np);
                bool:nc_digit = raw(is_digit(nc));
                if (nc_digit) {
                    np = np + 1i64;
                } else {
                    if (nc == 46i64) {     // '.' — decimal point
                        np = np + 1i64;
                    } else {
                        num_loop = false;
                    }
                }
            }
        }
        state[0i64] = np;
    }

    // ── Keyword tokens ──
    if (ch == 116i64) { tok = 9i64;  state[0i64] = pos + 4i64; }  // true
    if (ch == 102i64) { tok = 10i64; state[0i64] = pos + 5i64; }  // false
    if (ch == 110i64) { tok = 11i64; state[0i64] = pos + 4i64; }  // null

    ttypes[tc] = tok;
    state[2i64] = tc + 1i64;
    pass(tok);
};

// Tokenize entire input into ttypes[].  Stops after emitting EOF.
// Returns total token count (including the EOF token).
func:tokenize = int64(string:input, int64->:state, int64->:ttypes) {
    state[0i64] = 0i64;
    state[1i64] = string_length(input);
    state[2i64] = 0i64;
    state[3i64] = 0i64;

    bool:tok_loop = true;
    while (tok_loop) {
        int64:t = raw(next_tok(state, input, ttypes));
        if (t == 0i64) { tok_loop = false; }   // EOF reached
    }
    pass(state[2i64]);
};

// Compare ttypes[0..count-1] against expected[0..count-1].
func:seq_matches = bool(int64->:ttypes, int64:count, int64->:expected) {
    bool:all_match = true;
    int64:i = 0i64;
    while (i < count) {
        if (ttypes[i] != expected[i]) { all_match = false; }
        i = i + 1i64;
    }
    pass(all_match);
};

// ── Test runner ──────────────────────────────────────────────────────────────

func:main = int32() {
    // shared buffers (re-used across tests)
    wild int64->:state  = malloc(4i64 * 8i64);   // 4 x int64
    wild int64->:ttypes = malloc(64i64 * 8i64);  // up to 64 tokens per test case
    wild int64->:exp    = malloc(64i64 * 8i64);

