// ── init_board ───────────────────────────────────────────────────────────────
// Sets the board to the standard starting position.
func:init_board = NIL(wild int8->:b) {
    // Rank 0: white back rank  a1..h1
    b[0i64] = 4i8;   // R
    b[1i64] = 2i8;   // N
    b[2i64] = 3i8;   // B
    b[3i64] = 5i8;   // Q
    b[4i64] = 6i8;   // K
    b[5i64] = 3i8;   // B
    b[6i64] = 2i8;   // N
    b[7i64] = 4i8;   // R

    // Rank 1: white pawns  a2..h2
    int64:i = 8i64;
    while (i < 16i64) {
        b[i] = 1i8;
        i += 1i64;
    }

    // Ranks 2-5: empty
    while (i < 48i64) {
        b[i] = 0i8;
        i += 1i64;
    }

    // Rank 6: black pawns  a7..h7
    while (i < 56i64) {
        b[i] = 7i8;
        i += 1i64;
    }

    // Rank 7: black back rank  a8..h8
    b[56i64] = 10i8;  // r
    b[57i64] = 8i8;   // n
    b[58i64] = 9i8;   // b
    b[59i64] = 11i8;  // q
    b[60i64] = 12i8;  // k
    b[61i64] = 9i8;   // b
