    out[0i64] = h0 + a;
    out[1i64] = h1 + b;
    out[2i64] = h2 + c;
    out[3i64] = h3 + d;
    out[4i64] = h4 + e;
    out[5i64] = h5 + f;
    out[6i64] = h6 + g;
