    uint32:S1e = rot6 ^ rot11 ^ rot25;
    drop(print("ROTR6 (e) = "));
    drop(println(int32_toHex(rot6 => int32)));
    drop(print("ROTR11(e) = "));
    drop(println(int32_toHex(rot11 => int32)));
    drop(print("ROTR25(e) = "));
    drop(println(int32_toHex(rot25 => int32)));
    drop(print("Sigma1(e) = "));
    drop(println(int32_toHex(S1e => int32)));

    // Test 5: Ch(e, f, g) where e=0x510e527f, f=0x9b05688c, g=0x1f83d9ab
    uint32:f = 0x9b05688cu32;
    uint32:g = 0x1f83d9abu32;
