// philosophers.aria — Dining Philosophers (EXP-6)
//
// Classic Dijkstra concurrency problem: 5 philosophers, 5 forks.
// Forks are aria_atomic_int32 spinlocks (0=free, 1=held).
// Deadlock prevention: resource ordering (lower-index fork first).
//
// Build / run:
//   cd /home/randy/Workspace/REPOS/aria
//   ./build/ariac examples/philosophers/philosophers.aria --emit-llvm
//   clang -c examples/philosophers/phil_threads.c \
//         -I./include -o /tmp/phil_threads.o
//   clang++ -c examples/philosophers/philosophers.ll -o /tmp/philosophers.o
//   clang++ /tmp/philosophers.o /tmp/phil_threads.o \
//           build/libaria_runtime.a -latomic -lpthread \
//           -o examples/philosophers/philosophers
//   ./examples/philosophers/philosophers
//
// ARIA BUG LOG (EXP-6 discoveries):
//   Bug  #1: `wild T*` only valid in extern blocks; regular code must use `wild T->`
//   Bug  #2: `x => wild T->` cast NOT supported by the => operator
//   Bug  #3: Aria fn refs wrap result in Result<T>; can't pass to extern `wild int8*` param
//   Bug  #4: Workaround was `(int64)(int64):fn = my_fn` typed fn-ptr — but see Bug #12
//   Bug  #5: `if (cond) { stmt }` — no trailing `;` after `}`
//   Bug  #6: Module-level `wild int8->:g` globals → IR gen error "Unknown Aria type: int8@"
//   Bug  #7: pthread_t must be stored as int64; addressed as wild int64* for pthread FFI
//   Bug  #8: `raw(fn_returning_wild())` inline as extern arg → IR gen error
//   Bug  #9: Global `wild int8->` passed to Aria fn `wild int8->` param → IR error
//   Bug #10: Borrow checker: void(wild T*) fn name must end with _free/_destroy/_release/_close
//   Bug #11: `_ = non_void_extern(...)` silently removes the entire call from IR
//   Bug #12: `(T)(T):fn = named_func` — typed fn-ptr assignment never stores address in IR
//
// Bugs #11 and #12 make direct pthread FFI from Aria impossible in this compiler version.
// Workaround: phil_threads.c provides aria_spawn_philosophers() and
// aria_join_philosophers() as void() C helpers that do the actual threading.

use "../../stdlib/string_convert.aria".*;
use "../../stdlib/print_utils.aria".*;

// ── Memory ordering constants ─────────────────────────────────────────────────
func:RELAXED = int32() { pass(0); };
