// ── main ──────────────────────────────────────────────────────────────────────
func:main = int32() {
    // Allocate pools — cells: 200*3=600 int64s; env: 128*2=256 int64s
    wild int64->:cells = malloc(600i64 * 8i64);
    wild int64->:cnext = malloc(1i64 * 8i64);
    wild int64->:env   = malloc(256i64 * 8i64);
    wild int64->:etopp = malloc(1i64 * 8i64);

    cnext[0i64] = 0i64;
    etopp[0i64] = 0i64;

    // ── Build primitive cells (0–15) ─────────────────────────────────────────
    // tag=0:NIL  1:INT  2:SYM  3:CONS  4:LAMBDA  5:BUILTIN
    // cell_new(cells, cnext, tag, car, cdr)
    drop(raw(cell_new(cells, cnext, 0i64,  0i64,  0i64)));  // 0: NIL
    drop(raw(cell_new(cells, cnext, 1i64,  0i64,  0i64)));  // 1: INT(0)
    drop(raw(cell_new(cells, cnext, 1i64,  1i64,  0i64)));  // 2: INT(1)
    drop(raw(cell_new(cells, cnext, 1i64, 10i64,  0i64)));  // 3: INT(10)
    drop(raw(cell_new(cells, cnext, 5i64,  0i64,  0i64)));  // 4: BUILTIN(+)
    drop(raw(cell_new(cells, cnext, 5i64,  1i64,  0i64)));  // 5: BUILTIN(-)
    drop(raw(cell_new(cells, cnext, 5i64,  2i64,  0i64)));  // 6: BUILTIN(*)
    drop(raw(cell_new(cells, cnext, 5i64,  3i64,  0i64)));  // 7: BUILTIN(=)
    drop(raw(cell_new(cells, cnext, 2i64,  2i64,  0i64)));  // 8: SYM(if=2)
    drop(raw(cell_new(cells, cnext, 2i64,  1i64,  0i64)));  // 9: SYM(lambda=1)
    drop(raw(cell_new(cells, cnext, 2i64,  3i64,  0i64)));  // 10: SYM(n=3)
    drop(raw(cell_new(cells, cnext, 2i64,  4i64,  0i64)));  // 11: SYM(fact=4)
    drop(raw(cell_new(cells, cnext, 2i64,  5i64,  0i64)));  // 12: SYM(+=5)
    drop(raw(cell_new(cells, cnext, 2i64,  6i64,  0i64)));  // 13: SYM(-=6)
    drop(raw(cell_new(cells, cnext, 2i64,  7i64,  0i64)));  // 14: SYM(*=7)
    drop(raw(cell_new(cells, cnext, 2i64,  8i64,  0i64)));  // 15: SYM(==8)

    // ── Build program AST (cells 16–34) ──────────────────────────────────────
    // (= n 0) → cells 16–18 (built bottom-up)
    drop(raw(cell_new(cells, cnext, 3i64,  1i64,  0i64)));  // 16: CONS(INT0=1, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 10i64, 16i64)));  // 17: CONS(SYM_N=10, 16)
    drop(raw(cell_new(cells, cnext, 3i64, 15i64, 17i64)));  // 18: CONS(SYM_EQ=15, 17) = (= n 0)

    // (- n 1) → cells 19–21
    drop(raw(cell_new(cells, cnext, 3i64,  2i64,  0i64)));  // 19: CONS(INT1=2, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 10i64, 19i64)));  // 20: CONS(SYM_N=10, 19)
    drop(raw(cell_new(cells, cnext, 3i64, 13i64, 20i64)));  // 21: CONS(SYM_MINUS=13, 20) = (- n 1)

    // (fact (- n 1)) → cells 22–23
    drop(raw(cell_new(cells, cnext, 3i64, 21i64,  0i64)));  // 22: CONS((- n 1)=21, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 11i64, 22i64)));  // 23: CONS(SYM_FACT=11, 22) = (fact (- n 1))

    // (* n (fact (- n 1))) → cells 24–26
    drop(raw(cell_new(cells, cnext, 3i64, 23i64,  0i64)));  // 24: CONS((fact ...=23, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 10i64, 24i64)));  // 25: CONS(SYM_N=10, 24)
    drop(raw(cell_new(cells, cnext, 3i64, 14i64, 25i64)));  // 26: CONS(SYM_STAR=14, 25) = (* n ...)

    // (if (= n 0) 1 (* n (fact (- n 1)))) → cells 27–30
    drop(raw(cell_new(cells, cnext, 3i64, 26i64,  0i64)));  // 27: CONS(else=26, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64,  2i64, 27i64)));  // 28: CONS(then=INT1=2, 27)
    drop(raw(cell_new(cells, cnext, 3i64, 18i64, 28i64)));  // 29: CONS(test=(= n 0)=18, 28)
    drop(raw(cell_new(cells, cnext, 3i64,  8i64, 29i64)));  // 30: CONS(SYM_IF=8, 29) = lambda body

    // Lambda: params (n) → cell 31; LAMBDA cell → cell 32
    drop(raw(cell_new(cells, cnext, 3i64, 10i64,  0i64)));  // 31: CONS(SYM_N=10, NIL=0)
    drop(raw(cell_new(cells, cnext, 4i64, 31i64, 30i64)));  // 32: LAMBDA(params=31, body=30)

    // (fact 10) → cells 33–34
    drop(raw(cell_new(cells, cnext, 3i64,  3i64,  0i64)));  // 33: CONS(INT10=3, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 11i64, 33i64)));  // 34: CONS(SYM_FACT=11, 33) = (fact 10)

    // (fact 5): INT(5) → 35, list → 36, call → 37
    drop(raw(cell_new(cells, cnext, 1i64,  5i64,  0i64)));  // 35: INT(5)
    drop(raw(cell_new(cells, cnext, 3i64, 35i64,  0i64)));  // 36: CONS(INT5=35, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 11i64, 36i64)));  // 37: (fact 5)

    // (fact 0): reuse INT(0) cell 1, list → 38, call → 39
    drop(raw(cell_new(cells, cnext, 3i64,  1i64,  0i64)));  // 38: CONS(INT0=1, NIL=0)
    drop(raw(cell_new(cells, cnext, 3i64, 11i64, 38i64)));  // 39: (fact 0)

    // ── Populate environment ──────────────────────────────────────────────────
    // Slot 0: + (sym_id=5) → BUILTIN_PLUS cell 4
    env[0i64] = 5i64;   env[1i64] = 4i64;
    // Slot 1: - (sym_id=6) → BUILTIN_MINUS cell 5
    env[2i64] = 6i64;   env[3i64] = 5i64;
    // Slot 2: * (sym_id=7) → BUILTIN_STAR cell 6
    env[4i64] = 7i64;   env[5i64] = 6i64;
    // Slot 3: = (sym_id=8) → BUILTIN_EQ cell 7
    env[6i64] = 8i64;   env[7i64] = 7i64;
    // Slot 4: fact (sym_id=4) → LAMBDA cell 32
    env[8i64] = 4i64;   env[9i64] = 32i64;
    etopp[0i64] = 5i64;  // 5 bindings active

    // ── Test 1: (fact 10) = 3628800 ──────────────────────────────────────────
    int64:r10  = raw(eval(34i64, cells, cnext, env, etopp));
    int64:v10  = raw(ccar(cells, r10));
    drop(print("(fact 10) = "));
    drop(println(int32_toString(v10 => int32)));
    if (v10 == 3628800i64) { drop(println("PASS")); }
    if (v10 != 3628800i64) { drop(println("FAIL")); }

    // ── Test 2: (fact 5) = 120 ───────────────────────────────────────────────
    int64:r5   = raw(eval(37i64, cells, cnext, env, etopp));
    int64:v5   = raw(ccar(cells, r5));
    drop(print("(fact 5) = "));
    drop(println(int32_toString(v5 => int32)));
    if (v5 == 120i64) { drop(println("PASS")); }
    if (v5 != 120i64) { drop(println("FAIL")); }

    // ── Test 3: (fact 0) = 1 ─────────────────────────────────────────────────
    int64:r0   = raw(eval(39i64, cells, cnext, env, etopp));
    int64:v0   = raw(ccar(cells, r0));
    drop(print("(fact 0) = "));
    drop(println(int32_toString(v0 => int32)));
    if (v0 == 1i64) { drop(println("PASS")); }
    if (v0 != 1i64) { drop(println("FAIL")); }

    free(cells);
    free(cnext);
    free(env);
    free(etopp);
    pass(0i32);
};

