func:dg_opt_a = float64(float64:pbc, float64:pbm, float64:width) {
float64:factor   = raw(_dg_factor(pbm));
    float64:c        = pbc / width;
    float64:hw       = 0.5 * factor / 2.0;
    float64:lo       = c - hw;
    float64:hi       = c + hw;
    float64:chi      = raw(_dg_fmin(0.5, hi));
    float64:clo      = raw(_dg_fmax(0.0, lo));
    float64:overlap  = raw(_dg_fmax(0.0, chi - clo));
    float64:result   = raw(_dg_fmin(1.0, overlap / 0.5));
    pass(result);
};
```

