func:dgt_find_decision_changes = int64(wild float64->:snaps, wild int64->:meta, wild int64->:out_indices, int64:max_out) {
int64:count    = meta[3i64];
    int64:capacity = meta[1i64];
    int64:head     = meta[2i64];
    int64:found    = 0i64;
    int64:prev_dec = -1i64;
    int64:i        = 0i64;
    while (i < count) {
        int64:phys  = (head + i) % capacity;
        int64:base  = phys * 8i64;
        int64:dec_i = snaps[base + 6i64] => int64;
        if (prev_dec != -1i64) {
            if (dec_i != prev_dec) {
                if (found < max_out) {
                    out_indices[found] = i;
                    found = found + 1i64;
                }
            }
        }
        prev_dec = dec_i;
        i = i + 1i64;
    }
    pass(found);
};
```

