func:dgt_find_triggers = int64(wild float64->:snaps, wild int64->:meta, int64:axis_code, float64:threshold, wild int64->:out_indices, int64:max_out) {
int64:count    = meta[3i64];
    int64:capacity = meta[1i64];
    int64:head     = meta[2i64];
    int64:found    = 0i64;
    int64:i        = 0i64;
    int64:slot_off = 5i64;
    if (axis_code == 0i64) { slot_off = 4i64; }
    float64:prev_val = 0.0 - 999.0;
    while (i < count) {
        int64:phys  = (head + i) % capacity;
        int64:base  = phys * 8i64;
        float64:val = snaps[base + slot_off];
        if (prev_val > 0.0 - 998.0) {
            float64:diff = val - prev_val;
            if (diff < 0.0) { diff = 0.0 - diff; }
            if (diff > threshold) {
                if (found < max_out) {
                    out_indices[found] = i;
                    found = found + 1i64;
                }
            }
        }
        prev_val = val;
        i = i + 1i64;
    }
    pass(found);
};
```

