    // code
```

---

## Range Patterns

```aria
case 0..10:      // 0 to 9 (exclusive end)
    // code

case 0..=10:     // 0 to 10 (inclusive end)
    // code
```

---

## Fallthrough

```aria
case value1:
    // code
    fall;  // Continue to next case

case value2:
    // code
```

---

## Else Clause

```aria
pick value {
    case 1:
        // code
    else:
        // default (catches everything else)
```

---

## Complete Example

```aria
pick score {
    case 90..=100:
        grade = "A";

    case 80..=89:
        grade = "B";

    case 70..=79:
        grade = "C";

    case 60..=69:
        grade = "D";

    else:
        grade = "F";
```

---

## With Strings

```aria
