complex<fix256>:z2 = {real: fix256(-1), imag: fix256(-0, 001)};  // Just below cut

complex<fix256>:ln_z1 = complex_ln(z1);  // imag ≈ +π
complex<fix256>:ln_z2 = complex_ln(z2);  // imag ≈ -π

