// Greatest Common Divisor (GCD) using Euclidean algorithm
// This is what frac16 uses internally for normalization

fn:gcd_example = [tbb16:a, tbb16:b] -> tbb16 {
    // Make positive
    if (a < 0) { a = -a; }
    if (b < 0) { b = -b; }

    // Euclidean algorithm
    loop {
        if (b == 0) {
            break;
        }

        tbb16:temp = b;
        b = a % b;
        a = temp;
    }

    pass(a);
}

