## Example: RSA-8192 Key Validation

```aria
// Verify RSA-8192 key parameters
// n = p × q (where p, q are 4096-bit primes, but we can check with int2048 ops)

int2048:p_low = extract_low_2048_bits(rsa_prime_p);
int2048:q_low = extract_low_2048_bits(rsa_prime_q);

// Verify p and q are odd (necessary for primes > 2)
int2048:one = 1i2048;
int2048:p_is_odd = p_low & one;
int2048:q_is_odd = q_low & one;

if (p_is_odd != one || q_is_odd != one) {
    stderr.write("RSA primes must be odd!\n");
    !!! ERR_CRYPTO_PRIME_EVEN;
}

// Verify e and phi(n) are coprime
int2048:e = 65537i2048;
int2048:phi_low = extract_low_2048_bits(phi_n);

(int2048:gcd, int2048:_, int2048:_) = extended_gcd_2048(e, phi_low);

if (gcd != one) {
    stderr.write("Public exponent not coprime with phi(n)!\n");
    !!! ERR_CRYPTO_EXPONENT_INVALID;
}

// ✅ Key parameters valid
```

