// Event processing (2.1 billion events)
int32:event_count = 0i32;

till event_stream.has_more() loop
    Event:event = event_stream.read();
    event_count += 1i32;

    if (event_count < 0i32) {
        // Wrapped! (overflow detection)
        stderr.write("Event count overflow!\n");
        break;
    }
end

