vec3:point_b = vec3(40.0, 60.0, 70.0);

float:distance = point_a.distance(point_b);  
// sqrt((40-10)² + (60-20)² + (70-30)²) = sqrt(900 + 1600 + 1600) = 64.03

// Equivalent to:
